// Sub-region cartographic maps + utilities
export const S = 400;
export const sc = (d) => d.replace(/(\d+\.?\d*),(\d+\.?\d*)/g, (_, x, y) => `${parseFloat(x)*S},${parseFloat(y)*S}`);
export const pp = (pts) => pts.map((p,i) => `${i===0?"M":"L"}${p[0]*S},${p[1]*S}`).join(" ");

